import*as Browser from"@hyperjump/browser";import*as Instance from"../lib/instance.js";import{getKeywordName}from"../lib/experimental.js";const id="https://json-schema.org/keyword/draft-04/minimum",compile=async(e,r,t)=>{var o=getKeywordName(e.document.dialectId,"https://json-schema.org/keyword/draft-04/exclusiveMinimum"),o=await Browser.step(o,t),t=Browser.value(o);return[Browser.value(e),t]},interpret=([e,r],t)=>{if("number"!==Instance.typeOf(t))return!0;t=Instance.value(t);return r?e<t:e<=t};export default{id:id,compile:compile,interpret:interpret};